var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"걱정 마시죠, 마드모아젤. 이야기가 사실이라면 곧 풀려나실 겁니다.","JPN":"ご心配にはおよびませんよ、マドモアゼル。話が本当なら、すぐ釈放されるでしょう。","ENG":"Do not fret, mademoiselle. If your story is true, you will be released soon.","TWN":"別擔心。如果故事屬實，你很快就會被釋放了。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"기밀 유출 정도의 일을 알파트릭스 정도의 기업이 쉬이 넘어갈 리 없겠죠.","JPN":"機密漏洩くらいのことで、アルファトリックスほどの企業がそう簡単に処分を下すはずがありません。","ENG":"Alphatrix won't take top secrets leaking lightly.","TWN":"像阿爾法崔克斯這樣的企業，怎麼可能輕易放過真正的洩密者呢。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"정말 그럴까요?","JPN":"本当にそうなんでしょうか？","ENG":"Do you really think so?","TWN":"真的會這樣嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"물론이고 말고요. 여기서 조금만 기다리시면-","JPN":"もちろんですとも。ここでしばらくお待ちになっていればー","ENG":"Of course. Just wait here for a little bit, and–","TWN":"當然了。再在這裡等上一段時間——"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"무, 무슨 소리죠?","JPN":"な、何の音ですか？","ENG":"W-what was that?","TWN":"什，什麼聲音？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"아무래도 난동을 부리는 죄수가 있는 모양이군요.","JPN":"どうやら、暴れている囚人がいるようですね。","ENG":"There seems to be a prisoner who is causing some trouble.","TWN":"看來有犯人在鬧事啊。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"가끔씩 있는 일입니다. 수용소 인원들이라고 전부 순종적인 건 아니니까요.","JPN":"たまにあることです。収容所の人は、皆が大人しいわけではありません。","ENG":"This happens from time to time. Not everyone in prison is obedient.","TWN":"偶爾會發生這種事。畢竟收容所裡的人並不都是逆來順受的。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"금방 잠잠해질 테니, 너무 걱정 말고-","JPN":"すぐに治まるはずですから、あまり心配しないでー","ENG":"It will calm down soon, so don't worry and–","TWN":"很快就會平靜下來的，不用太擔心……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"…말을 아끼겠습니다. 제가 한 건 아니지만 죄를 진 기분이군요.","JPN":"……言葉を惜しみましょう。僕の所業ではなくとも、罪を犯したような気分です。","ENG":"...I shouldn't jinx it. I feel somehow guilty for that.","TWN":"……我就不烏鴉嘴了。雖然不是我做的，但總感覺有些愧疚。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그렇지만 그라운드 원 한복판에서 대체 누가 이런 짓을?","JPN":"でも、グラウンド・ワンのど真ん中でいったい誰がこんなことを？","ENG":"But who would do that in the middle of Ground One?","TWN":"呃，不過到底是誰會在G1中心幹這種事？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RIBBON_DEBT_NPC_NULL","text":{"KOREA":"찾-았-다.","JPN":"みーつーけーた。","ENG":"Found you.","TWN":"找——到——了。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"이… 이 트라우마를 자극하는 낯익은 목소리는…….","JPN":"こ……この、トラウマを刺激する聞きなれた声は……","ENG":"T-this trauma-triggering voice is...","TWN":"這……這個讓人害怕的熟悉聲音是……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"그렇습니다. 동료애가 넘치는 자상한 크레데레입니다.","JPN":"そうです。仲間愛の溢れる優しいクレデレです。","ENG":"Yes. It is Credere, the kind and the compassionate.","TWN":"沒錯，是充滿同伴情誼的溫柔克蕾妲莉！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L23_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"늦어서 죄송합니다, 유피. 이것저것 처리하느라 조금 늦었습니다.","JPN":"遅れてすみません、ユピ。あれこれ処理していて、ちょっと遅くなりました。","ENG":"Sorry for the delay, Yuppie. It took a while to take care of some things.","TWN":"對不起，悠菲。處理其他事情耽誤了一點時間。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"크레데레? 여긴 어떻게 온 거예요?","JPN":"クレデレ？　ここにはどうやって来たんですか？","ENG":"Credere? How did you get here?","TWN":"克蕾妲莉？你怎麼會來這裡？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"유피에게 사과하러 왔습니다.","JPN":"ユピに謝りに来ました。","ENG":"Credere is here to apologize to you.","TWN":"克蕾妲莉來向悠菲道歉。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"크레데레가 의도한 건 아니지만 큰 폐를 끼쳤어요.","JPN":"クレデレは意図していなかったんですけど、大変ご迷惑をおかけして。","ENG":"Credere didn't intend it, but Credere was a nuisance.","TWN":"雖然並不是有意的，但還是給悠菲添了大麻煩。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"고작 그런 것 때문에 몰래 숨어든 거예요? 여긴 수용소라고요!","JPN":"そんなことのためにこっそり忍び込んだんですか？　ここは収容所ですよ！","ENG":"That's why you sneaked in here? This is prison!","TWN":"就因為這種事溜進來？這裡可是收容所啊！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"전 괜찮으니까 돌아가세요. 수용소에 뭔가 문제가 생긴 것 같다고요.","JPN":"私は大丈夫ですから、帰ってください。収容所に何か問題が起こったみたいです。","ENG":"I'm okay, so go back. There seems to be something going on here.","TWN":"我沒事，你們快回去吧。收容所好像出了什麼問題。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"안 됩니다. 크레데레는 유피에게 사과해야 합니다.","JPN":"ダメです。クレデレはユピに謝らないといけません。","ENG":"No. Credere has to apologize to Yuppie.","TWN":"不行，克蕾妲莉必須向悠菲道歉。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"정말 괜찮다니까요? 얘기라면 다음에 해도 충분하잖아요.","JPN":"本当に大丈夫ですってば。話なら今度すればいいでしょう？","ENG":"I'm really fine. We can talk later.","TWN":"真的沒關係啦？有什麼話以後再說吧？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"유피가 어디 있는지 몰라서 감방을 죄다 부숴버렸습니다.","JPN":"ユピがどこにいるのかわからなくて、監房を全部壊しました。","ENG":"Credere destroyed all the cells because Credere didn't know where Yuppie was.","TWN":"克蕾妲莉不知道悠菲在哪裡，所以把牢房全都敲開了。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"대탈출쇼가 졸지에 대탈옥쇼가 되어버렸어요.","JPN":"大脱出ショーが、大脱獄ショーになっちゃいました。","ENG":"The great escape plan became the great prison break plan.","TWN":"本來是要救你出去的，結果變成越獄風雲。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"끼야하-! 자유다!!","JPN":"キャッハー！　自由だ！！","ENG":"Hahaha! We're free!","TWN":"哈哈哈哈——！自由了！！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_ELECTRIC_BIG_02"},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"전부 부숴! 우릴 억압하던 놈들에게 복수하는 거다!!","JPN":"全部ぶっ壊せ！　俺たちを抑えてたやつらに復讐するんだ！！","ENG":"Destroy everything! We're taking revenge on the bastards who have been oppressing us!","TWN":"全都砸爛！向那些壓迫我們的傢伙復仇！！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_RIFLE_FIRE_02"},{"id":"L36_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"너였냐-!!","JPN":"お前だったのかー！！","ENG":"That was YOUR DOING?!","TWN":"是你做的嗎——!!"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_05"},{"id":"L37_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"크레데레는 귀여우니 봐주시죠. 솔직히 이건 유피 잘못도 있습니다.","JPN":"クレデレは可愛いから、大目に見てください。正直、これはユピも悪いんです。","ENG":"Credere is cute, so let's move on. Honestly, this is partly your fault.","TWN":"克蕾妲莉這麼可愛，所以可以被原諒。而且說實話，悠菲其實也有錯的。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L38_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"입구 쪽에 계실 것이지. 왜 이런 끝자락에 갇혀 있던 건가요?","JPN":"入口の方にいれば良かったのに。どうしてこんな隅に閉じ込められていたんですか？","ENG":"You could've been locked up near the entrance. Why did you have to be so far inside?","TWN":"悠菲應該待在入口那邊的，為什麼會被關在最裡面呢？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"들어온 순서대로 배정되니까 당연히 뒤쪽이겠죠!!","JPN":"入った順番ですから、そりゃ奥になるでしょう！！","ENG":"We're assigned based on when we get incarcerated, so, of course, I'm in the back!","TWN":"因為是按進來的順序分配的，當然是在後面！！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"아하.","JPN":"なるほど。","ENG":"A-ha.","TWN":"啊。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"그래도 걱정 마시죠. 작전에는 지장 없습니다.","JPN":"でも、心配しないでください。作戦には問題ありません。","ENG":"Don't worry, though. It is still going as planned.","TWN":"不過不用擔心。作戰不會受到影響。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"아니, 그냥 얌전히 있으면…!!","JPN":"いや、別に大人しくしていれば……！！","ENG":"No, just stay still, and–","TWN":"不，你就乖乖待著……！！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"얍.","JPN":"やあっ。","ENG":"Poof.","TWN":"咻砰。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"콜록콜록…!","JPN":"ゲホゲホ……！","ENG":"*Cough* *Cough*","TWN":"咳咳，咳咳……！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"미쳤어요? 감옥문을 날려 버리면 어쩌자는 거야?","JPN":"正気ですか！？　牢獄の扉をぶっ飛ばしてどうするの！","ENG":"Are you crazy? You can't just blow up the prison door!","TWN":"你瘋了嗎？把監獄門炸飛是想幹什麼？"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"전과자인 유피가 이런 일에 얽혔으니 몇 달은 경찰서를 들락거려야 할 겁니다.","JPN":"前科者のユピがこんなことに関わってるから､数カ月は警察署に通わないとダメでしょう。","ENG":"Yuppie, you have a criminal record, and with the new incident, you would have to frequent the police station for months.","TWN":"如果有前科的悠菲捲進了這種事，恐怕要在警察局待幾個月了。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"유피가 일을 못하면 보육원 아이들도 쫄쫄 굶겠죠.","JPN":"ユピが仕事できないと、孤児院の子どもたちも飢えてしまうでしょうね。","ENG":"If you are not able to work, the kids at the orphanage will starve.","TWN":"如果悠菲不能工作，育幼院的孩子們也會餓肚子的。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그, 그건 또 어떻게 안 거예요?","JPN":"そ、それはどうやって知ったんですか？","ENG":"H-how did you know about that?","TWN":"你、你又是怎麼知道的？"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"시그마와 함께 유피에 대해 알아봤습니다.","JPN":"シグマと一緒にユピのことを調べました。","ENG":"Credere did some research on you with Sigma.","TWN":"克蕾妲莉和西格瑪一起做了調查。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"돈도 없으면서 월급의 대부분을 보육원으로 송금하시더군요.","JPN":"お金もないのに給料のほとんどを孤児院に送金していました。","ENG":"You are broke, and yet you send most of your income to the orphanage.","TWN":"明明沒錢，卻把大部分工資都匯給了育幼院。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"기특한 유피에게 칭찬도장 하나를 드리겠습니다.","JPN":"健気なユピによくできましたステッカーを一つ差し上げましょう。","ENG":"Here is another stamp for Yuppie, who did something commendable.","TWN":"克蕾妲莉要給乖巧的悠菲一個好寶寶印章。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"거 더럽게 고맙네요, 진짜.","JPN":"それはありがたいですね、マジでっ。","ENG":"Wow. Thank you so much.","TWN":"真是謝囉！"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"마드모아젤. 이, 이건…….","JPN":"マドモアゼル。こ、これは……","ENG":"Mademoiselle. Th-this is...","TWN":"小姐。這、這是……"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"젠장…! 수용소가 완전 개판이 되어버렸잖아?","JPN":"くそ……！　収容所がめちゃくちゃになっちゃってるじゃない。","ENG":"Damn it...! The prison has become a mess!","TWN":"天啊……！ 收容所完全亂成一團了吧?"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"잘 들어요, 크레데레. 아무리 그래도 이런 상황에서 탈옥할 수는 없어요.","JPN":"ちゃんと聞いてください、クレデレ。いくらなんでも、こんな状況で脱獄するわけにはいきません。","ENG":"Listen, Credere. Even so, I can't break out of prison in a situation like this.","TWN":"聽好了，克蕾妲莉。不管怎樣，在這種情況下是不可能越獄的。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"하다못해 최소한의 수습은 해야 한다고요, 제 말 무슨 말인지 이해하겠어요?","JPN":"少なくとも、最低限の後始末はしないと。私の言葉がどういうことかわかりました？","ENG":"I have to do what I can to sort this out. Do you understand what I mean?","TWN":"至少也要做最基本的善後工作，你明白我的意思嗎？"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"무얼 숨기랴. 크레데레의 이름은 신뢰라는 뜻입니다.","JPN":"何を隠そう。クレデレの名前は信頼という意味を持っています。","ENG":"No skeletons in this closet. Credere's name means trust.","TWN":"克蕾妲莉沒有秘密。克蕾妲莉的名字就是信賴的意思。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L25_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"유피는 아무 걱정 말고 저만 믿으시길.","JPN":"ユピは何の心配もせず、私だけを信じてください。","ENG":"Don't worry, Yuppie. Just count on Credere.","TWN":"悠菲，儘管放心，相信我就好。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"퍽이나 신뢰 가는 말이네요, 그것참.","JPN":"それはそれは、頼もしいですねっ、まったく。","ENG":"Wow. Sounds so trustworthy.","TWN":"我就是太相信你了。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};